import{_ as e,c as o,o as t,a1 as i}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Introdução do Plugin: Recursos e Riscos | Antigravity Auth","description":"Aprenda o valor principal e os avisos de risco do plugin Antigravity Auth. Acesse os modelos Claude e Gemini 3 via Google OAuth com suporte a balanceamento de carga entre múltiplas contas.","frontmatter":{"title":"Introdução do Plugin: Recursos e Riscos | Antigravity Auth","sidebarTitle":"Este plugin é para você","subtitle":"Entenda o valor principal do plugin Antigravity Auth","description":"Aprenda o valor principal e os avisos de risco do plugin Antigravity Auth. Acesse os modelos Claude e Gemini 3 via Google OAuth com suporte a balanceamento de carga entre múltiplas contas.","tags":["Primeiros passos","Introdução do plugin","OpenCode","Antigravity"],"order":1},"headers":[],"relativePath":"pt/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md","filePath":"pt/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md"}'),s={name:"pt/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md"};function r(n,a,l,d,c,u){return t(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="entenda-o-valor-principal-do-plugin-antigravity-auth" tabindex="-1">Entenda o Valor Principal do Plugin Antigravity Auth <a class="header-anchor" href="#entenda-o-valor-principal-do-plugin-antigravity-auth" aria-label="Permalink to &quot;Entenda o Valor Principal do Plugin Antigravity Auth&quot;">​</a></h1><p><strong>Antigravity Auth</strong> é um plugin do OpenCode que acessa a Antigravity API através de autenticação OAuth do Google. Ele permite que você use sua conta Google familiar para chamar modelos avançados como Claude Opus 4.5, Sonnet 4.5 e Gemini 3 Pro/Flash, sem precisar gerenciar chaves de API. O plugin também oferece recursos como balanceamento de carga entre múltiplas contas, pools duplos de quota e recuperação automática de sessão, sendo ideal para usuários que precisam de modelos avançados e gerenciamento automático.</p><h2 id="o-que-voce-vai-aprender" tabindex="-1">O Que Você Vai Aprender <a class="header-anchor" href="#o-que-voce-vai-aprender" aria-label="Permalink to &quot;O Que Você Vai Aprender&quot;">​</a></h2><ul><li>Determinar se este plugin é adequado para o seu cenário de uso</li><li>Conhecer quais modelos de IA e recursos principais o plugin suporta</li><li>Entender os riscos e precauções ao usar este plugin</li><li>Decidir se deve continuar com a instalação e configuração</li></ul><h2 id="seu-problema-atual" tabindex="-1">Seu Problema Atual <a class="header-anchor" href="#seu-problema-atual" aria-label="Permalink to &quot;Seu Problema Atual&quot;">​</a></h2><p>Você quer usar os modelos de IA mais avançados (como Claude Opus 4.5, Gemini 3 Pro), mas o acesso oficial é limitado. Procura uma forma confiável de obter esses modelos, ao mesmo tempo que deseja:</p><ul><li>Não precisar gerenciar manualmente múltiplas chaves de API</li><li>Poder alternar contas automaticamente quando encontrar limites de taxa</li><li>Recuperar automaticamente conversas interrompidas sem perder o contexto</li></ul><h2 id="ideia-central" tabindex="-1">Ideia Central <a class="header-anchor" href="#ideia-central" aria-label="Permalink to &quot;Ideia Central&quot;">​</a></h2><p><strong>Antigravity Auth</strong> é um plugin do OpenCode que acessa a Google Antigravity API através de <strong>autenticação OAuth do Google</strong>, permitindo que você use sua conta Google familiar para chamar modelos de IA avançados.</p><p>Ele não age como proxy para todas as requisições, mas <strong>intercepta e converte</strong> suas chamadas de modelo, encaminhando-as para a Antigravity API e convertendo as respostas de volta para um formato que o OpenCode possa reconhecer.</p><h2 id="recursos-principais" tabindex="-1">Recursos Principais <a class="header-anchor" href="#recursos-principais" aria-label="Permalink to &quot;Recursos Principais&quot;">​</a></h2><h3 id="modelos-suportados" tabindex="-1">Modelos Suportados <a class="header-anchor" href="#modelos-suportados" aria-label="Permalink to &quot;Modelos Suportados&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Família de Modelos</th><th>Modelos Disponíveis</th><th>Características</th></tr></thead><tbody><tr><td><strong>Claude</strong></td><td>Opus 4.5, Sonnet 4.5</td><td>Suporte ao modo de pensamento estendido</td></tr><tr><td><strong>Gemini 3</strong></td><td>Pro, Flash</td><td>Integração com Google Search, pensamento estendido</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Modo de Pensamento (Thinking)</p><p>Os modelos Thinking realizam um &quot;pensamento profundo&quot; antes de gerar respostas, mostrando o processo de raciocínio. Você pode configurar o orçamento de pensamento para equilibrar qualidade e velocidade de resposta.</p></div><h3 id="balanceamento-de-carga-entre-multiplas-contas" tabindex="-1">Balanceamento de Carga entre Múltiplas Contas <a class="header-anchor" href="#balanceamento-de-carga-entre-multiplas-contas" aria-label="Permalink to &quot;Balanceamento de Carga entre Múltiplas Contas&quot;">​</a></h3><ul><li><strong>Suporta até 10 contas Google</strong></li><li>Alterna automaticamente para a próxima conta quando encontra limites de taxa (erro 429)</li><li>Três estratégias de seleção de conta: sticky (fixo), round-robin (rodízio), hybrid (híbrido inteligente)</li></ul><h3 id="sistema-de-quotas-duplas" tabindex="-1">Sistema de Quotas Duplas <a class="header-anchor" href="#sistema-de-quotas-duplas" aria-label="Permalink to &quot;Sistema de Quotas Duplas&quot;">​</a></h3><p>O plugin acessa <strong>dois pools independentes de quotas</strong> simultaneamente:</p><ol><li><strong>Quota Antigravity</strong>: Da Google Antigravity API</li><li><strong>Quota Gemini CLI</strong>: Do Google Gemini CLI</li></ol><p>Quando um pool atinge o limite, o plugin tenta automaticamente o outro, maximizando a utilização da quota.</p><h3 id="recuperacao-automatica-de-sessao" tabindex="-1">Recuperação Automática de Sessão <a class="header-anchor" href="#recuperacao-automatica-de-sessao" aria-label="Permalink to &quot;Recuperação Automática de Sessão&quot;">​</a></h3><ul><li>Detecta falhas em chamadas de ferramentas (como interrupções por ESC)</li><li>Injeta automaticamente tool_result sintético para evitar falhas na conversa</li><li>Suporta envio automático de &quot;continue&quot; para retomar a conversa</li></ul><h3 id="integracao-com-google-search" tabindex="-1">Integração com Google Search <a class="header-anchor" href="#integracao-com-google-search" aria-label="Permalink to &quot;Integração com Google Search&quot;">​</a></h3><p>Ativa a pesquisa na web para modelos Gemini, melhorando a precisão factual:</p><ul><li><strong>Modo Auto</strong>: O modelo decide quando pesquisar com base na necessidade</li><li><strong>Modo Always-on</strong>: Pesquisa em todas as consultas</li></ul><h2 id="quando-usar-este-plugin" tabindex="-1">Quando Usar Este Plugin <a class="header-anchor" href="#quando-usar-este-plugin" aria-label="Permalink to &quot;Quando Usar Este Plugin&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Adequado para estes cenários</p><ul><li>Você tem múltiplas contas Google e deseja aumentar a quota total</li><li>Precisa usar modelos Thinking do Claude ou Gemini 3</li><li>Quer ativar o Google Search para modelos Gemini</li><li>Não quer gerenciar chaves de API manualmente, prefere autenticação OAuth</li><li>Encontra frequentemente limites de taxa e deseja alternação automática de contas</li></ul></div><div class="warning custom-block"><p class="custom-block-title">Não adequado para estes cenários</p><ul><li>Você precisa usar modelos não oficialmente divulgados pelo Google</li><li>É muito sensível aos riscos dos Termos de Serviço do Google (veja avisos de risco abaixo)</li><li>Apenas precisa de modelos básicos Gemini 1.5 ou Claude 3 (as interfaces oficiais são mais estáveis)</li><li>Você abre navegadores com dificuldade em ambientes WSL, Docker, etc.</li></ul></div><h2 id="⚠️-aviso-importante-de-risco" tabindex="-1">⚠️ Aviso Importante de Risco <a class="header-anchor" href="#⚠️-aviso-importante-de-risco" aria-label="Permalink to &quot;⚠️ Aviso Importante de Risco&quot;">​</a></h2><p>Usar este plugin <strong>pode violar os Termos de Serviço do Google</strong>. Alguns usuários relataram que suas contas Google foram <strong>banidas</strong> ou <strong>banidas silenciosamente</strong> (acesso restrito sem notificação clara).</p><h3 id="cenarios-de-alto-risco" tabindex="-1">Cenários de Alto Risco <a class="header-anchor" href="#cenarios-de-alto-risco" aria-label="Permalink to &quot;Cenários de Alto Risco&quot;">​</a></h3><ul><li>🚨 <strong>Contas Google novas</strong>: Probabilidade muito alta de banimento</li><li>🚨 <strong>Contas com assinatura Pro/Ultra recém-ativada</strong>: Fácil de serem marcadas e banidas</li></ul><h3 id="por-favor-confirme-antes-de-usar" tabindex="-1">Por Favor Confirme Antes de Usar <a class="header-anchor" href="#por-favor-confirme-antes-de-usar" aria-label="Permalink to &quot;Por Favor Confirme Antes de Usar&quot;">​</a></h3><ul><li>Esta é uma <strong>ferramenta não oficial</strong>, não aprovada pelo Google</li><li>Sua conta pode ser suspensa ou banida permanentemente</li><li>Você assume todos os riscos ao usar este plugin</li></ul><h3 id="recomendacoes" tabindex="-1">Recomendações <a class="header-anchor" href="#recomendacoes" aria-label="Permalink to &quot;Recomendações&quot;">​</a></h3><ul><li>Use <strong>contas Google maduras</strong>, não crie novas contas especificamente para este plugin</li><li>Evite usar contas importantes vinculadas a serviços críticos</li><li>Se sua conta for banida, não há como recorrer através deste plugin</li></ul><div class="danger custom-block"><p class="custom-block-title">Segurança da Conta</p><p>Todos os tokens OAuth são armazenados localmente em <code>~/.config/opencode/antigravity-accounts.json</code>, não são enviados para nenhum servidor. Mas por favor mantenha seu computador seguro para evitar vazamento de tokens.</p></div><h2 id="resumo-da-licao" tabindex="-1">Resumo da Lição <a class="header-anchor" href="#resumo-da-licao" aria-label="Permalink to &quot;Resumo da Lição&quot;">​</a></h2><p>Antigravity Auth é um poderoso plugin do OpenCode que permite acessar modelos avançados Claude e Gemini 3 através de OAuth do Google. Ele oferece recursos como balanceamento de carga entre múltiplas contas, pools duplos de quota e recuperação automática de sessão, sendo ideal para usuários que precisam de modelos avançados e gerenciamento automático.</p><p>Mas por favor esteja ciente: <strong>há risco de banimento ao usar este plugin</strong>. Use contas Google não críticas e entenda os riscos antes de continuar com a instalação.</p><h2 id="proxima-licao" tabindex="-1">Próxima Lição <a class="header-anchor" href="#proxima-licao" aria-label="Permalink to &quot;Próxima Lição&quot;">​</a></h2><blockquote><p>Na próxima lição vamos aprender a <strong><a href="./../quick-install/">Instalação Rápida</a></strong>.</p><p>Você vai aprender:</p><ul><li>Instalar o plugin em 5 minutos</li><li>Adicionar sua primeira conta Google</li><li>Verificar se a instalação foi bem-sucedida</li></ul></blockquote>',42)])])}const g=e(s,[["render",r]]);export{p as __pageData,g as default};
